parameters.jsonBody:
={
  "model": "{{ $('GetBasicConfig').item.json['sd-endpoint'] }}",
  "content": [
    {
      "type": "text",
      "text": "{{ JSON.stringify($('循环').item.json.prompt).slice(1, -1) }}"
    },{{ JSON.stringify($('AI Agent').item.json.output).slice(1, -1) }}
  ],
  "generate_audio": true,
  "resolution": "{{ $('Set Prompt').item.json['分辨率'] }}",
  "ratio": "{{ $('Set Prompt').item.json['画幅比例'] }}",
  "duration": {{ $('循环').item.json.duration }},
  "watermark": false,
  "seed": {{ $('GetBasicConfig').item.json.global_seed }}
}

={
  "systemInstruction": {
    "role": "system",
    "parts": [
      {
        "text": "{{ JSON.stringify($json.system).slice(1, -1) }}"
      }
    ]
  },
  "contents": [
    {
      "role": "user",
      "parts": [
        {
          "text": "{{ JSON.stringify($json.prompt).slice(1, -1) }}"
        }
      ]
    }
  ],
  "generationConfig": {
    "maxOutputTokens": 65535,
    "temperature": 0.9,
    "thinkingConfig": {
      "thinkingBudget": 30000
    },
    "responseMimeType": "application/json",
    "responseSchema":{
  "type": "OBJECT",
  "properties": {
    "storyboards": {
      "type": "ARRAY",
      "items": {
        "type": "OBJECT",
        "properties": {
          "storyboard_id": {
            "type": "STRING",
            "description": "分镜唯一编号，如 s001、s002，或沿用用户给定镜号。"
          },
          "duration": {
            "type": "INTEGER",
            "description": "单分镜时长，只允许 10 到 15 的整数。"
          },
          "prompt": {
            "type": "STRING",
            "description": "可直接用于 Seedance 2.0 的单分镜完整提示词。"
          },
          "asset_bindings": {
            "type": "ARRAY",
            "description": "本分镜实际使用的资产绑定，顺序必须与 prompt 中首次出现顺序一致。",
            "items": {
              "type": "OBJECT",
              "properties": {
                "index_label": {
                  "type": "STRING",
                  "description": "图号标签，例如 图1、图2、图3。"
                },
                "asset_name": {
                  "type": "STRING",
                  "description": "资产名称，例如 豪宅、爷爷、姑妈、Lina。"
                },
                "asset_uri": {
                  "type": "STRING",
                  "description": "标准化后的资产 URI，格式必须是 asset://<ASSET_ID>。"
                }
              },
              "required": [
                "index_label",
                "asset_name",
                "asset_uri"
              ]
            }
          },
          "seedance_content_items": {
            "type": "ARRAY",
            "description": "可直接插入 Seedance content 数组的参考图对象，顺序必须与 asset_bindings 完全一致。",
            "items": {
              "type": "OBJECT",
              "properties": {
                "type": {
                  "type": "STRING",
                  "enum": [
                    "image_url"
                  ]
                },
                "image_url": {
                  "type": "OBJECT",
                  "properties": {
                    "url": {
                      "type": "STRING",
                      "description": "标准 asset URI，格式 asset://<ASSET_ID>。"
                    }
                  },
                  "required": [
                    "url"
                  ]
                },
                "role": {
                  "type": "STRING",
                  "enum": [
                    "reference_image"
                  ]
                }
              },
              "required": [
                "type",
                "image_url",
                "role"
              ]
            }
          }
        },
        "required": [
          "storyboard_id",
          "duration",
          "prompt",
          "asset_bindings",
          "seedance_content_items"
        ]
      }
    }
  },
  "required": [
    "storyboards"
  ]
}
  }
}

